import { Box, Paper, Stack, Typography } from '@mui/material';
import Button from '@mui/material/Button';
import FavoriteRoundedIcon from '@mui/icons-material/FavoriteRounded';
import HomeRoundedIcon from '@mui/icons-material/HomeRounded';
import LocalFireDepartmentRoundedIcon from '@mui/icons-material/LocalFireDepartmentRounded';
import RestaurantMenuRoundedIcon from '@mui/icons-material/RestaurantMenuRounded';
import SoupKitchenRoundedIcon from '@mui/icons-material/SoupKitchenRounded';
import { glassPanelSx } from '../utils/glassPanel';

type ViewMode = 'home' | 'recipes' | 'favorites';

interface RecipeHeaderProps {
  activeView: ViewMode;
  onChangeView: (view: ViewMode) => void;
}

export default function RecipeHeader({
  activeView,
  onChangeView,
}: RecipeHeaderProps) {
  return (
    <Paper elevation={0} sx={{ p: { xs: 1.5, md: 2 }, mb: 2, borderRadius: 4, ...glassPanelSx() }}>
      <Stack
        direction={{ xs: 'column', md: 'row' }}
        spacing={1.5}
        alignItems={{ xs: 'flex-start', md: 'center' }}
        justifyContent="space-between"
      >
        <Box>
          <Stack direction="row" alignItems="center" spacing={1} sx={{ mb: 0.5 }}>
            <Box
              sx={{
                width: 34,
                height: 34,
                borderRadius: '50%',
                display: 'grid',
                placeItems: 'center',
                background: 'linear-gradient(135deg, rgba(123, 209, 255, 0.35), rgba(118, 232, 208, 0.2))',
                border: '1px solid rgba(166, 210, 245, 0.35)',
              }}
            >
              <SoupKitchenRoundedIcon color="primary" fontSize="small" />
            </Box>
            <LocalFireDepartmentRoundedIcon sx={{ color: '#ff9b5f' }} fontSize="small" />
            <Typography variant="h4" fontWeight={800}>
              RecipeBox Pro
            </Typography>
          </Stack>
          <Typography variant="caption" color="text.secondary">
            Cook. Save. Serve.
          </Typography>
        </Box>

        <Stack direction={{ xs: 'column', sm: 'row' }} spacing={1} sx={{ width: { xs: '100%', md: 'auto' } }}>
          <Stack direction="row" spacing={1} sx={{ flexWrap: 'wrap' }}>
            <Button
              startIcon={<HomeRoundedIcon />}
              variant={activeView === 'home' ? 'contained' : 'text'}
              onClick={() => onChangeView('home')}
              sx={{ minHeight: 34 }}
            >
              Home
            </Button>
            <Button
              startIcon={<RestaurantMenuRoundedIcon />}
              variant={activeView === 'recipes' ? 'contained' : 'text'}
              onClick={() => onChangeView('recipes')}
              sx={{ minHeight: 34 }}
            >
              Recipes
            </Button>
            <Button
              startIcon={<FavoriteRoundedIcon />}
              variant={activeView === 'favorites' ? 'contained' : 'text'}
              onClick={() => onChangeView('favorites')}
              sx={{ minHeight: 34 }}
            >
              Favorites
            </Button>
          </Stack>
        </Stack>
      </Stack>
    </Paper>
  );
}
